/**
 * @summary List AI-generated messages for a lead
 */
export const getListLeadMessagesUrl = (
  workspaceId: string,
  leadId: string,
  params?: ListLeadMessagesParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/workspaces/${workspaceId}/leads/${leadId}/messages?${stringifiedParams}`
    : `/api/workspaces/${workspaceId}/leads/${leadId}/messages`;
};

